// JSON 파싱1 - AI Agent 출력(여러 아이템)의 output을 전부 파싱해서 합치기
// - 각 item.json.output 에 들어있는 "문자열 JSON 배열" 파싱
// - ```json ...``` 코드펜스 제거
// - JSON 외 잡문이 섞여도 첫 JSON 배열/객체를 브레이스 매칭으로 추출 시도
// - 결과 0개여도 최소 1개 아이템을 반환해 No output 방지(옵션)

// =======================
// 유틸
// =======================
function asText(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

function stripCodeFences(s) {
  return String(s || '')
    .replace(/```(?:json)?\s*/gi, '')
    .replace(/```/g, '')
    .trim();
}

// 텍스트 안에서 첫 JSON 배열/객체를 브레이스/브라켓 매칭으로 뽑아냄
function extractFirstJson(text) {
  const s = String(text || '');
  const startArr = s.indexOf('[');
  const startObj = s.indexOf('{');

  // 배열/객체 중 더 먼저 나오는 시작점 선택
  let start = -1;
  let mode = '';
  if (startArr >= 0 && startObj >= 0) {
    start = Math.min(startArr, startObj);
    mode = (start === startArr) ? 'arr' : 'obj';
  } else if (startArr >= 0) {
    start = startArr; mode = 'arr';
  } else if (startObj >= 0) {
    start = startObj; mode = 'obj';
  } else {
    return '';
  }

  let depth = 0;
  let inString = false;
  let escape = false;

  const openChar = (mode === 'arr') ? '[' : '{';
  const closeChar = (mode === 'arr') ? ']' : '}';

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (inString) {
      if (escape) {
        escape = false;
      } else if (ch === '\\') {
        escape = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    } else {
      if (ch === '"') {
        inString = true;
        continue;
      }
      if (ch === openChar) depth++;
      if (ch === closeChar) depth--;

      if (depth === 0 && i >= start) {
        return s.slice(start, i + 1);
      }
    }
  }

  return '';
}

function tryParseJson(s) {
  const t = stripCodeFences(asText(s)).trim();
  if (!t) return null;

  // 1) 그대로 JSON 파싱 시도
  try { return JSON.parse(t); } catch (e) {}

  // 2) 텍스트에서 첫 JSON 덩어리 추출 후 파싱
  const extracted = extractFirstJson(t);
  if (extracted) {
    try { return JSON.parse(extracted); } catch (e) {}
  }

  return null;
}

// 중복 제거 키(출처_URL 우선, 없으면 우수사례명+날짜)
function makeKey(o) {
  const url = (o && o['출처_URL']) ? String(o['출처_URL']).trim() : '';
  const name = (o && o['우수사례명']) ? String(o['우수사례명']).trim() : '';
  const date = (o && o['날짜']) ? String(o['날짜']).trim() : '';
  return url || `${name}__${date}`;
}

// =======================
// 메인
// =======================
const inputItems = $input.all();
let merged = [];

for (let idx = 0; idx < inputItems.length; idx++) {
  const j = inputItems[idx].json || {};
  const raw = j.output ?? j.text ?? j.result ?? j;

  const parsed = tryParseJson(raw);

  if (Array.isArray(parsed)) {
    merged.push(...parsed);
  } else if (parsed && typeof parsed === 'object') {
    merged.push(parsed);
  } else {
    // 파싱 실패 시 스킵(원하면 로그)
    console.log(`[JSON 파싱1] item ${idx}: parse failed`);
  }
}

// 빈/이상치 제거(객체만 남김)
merged = merged.filter(v => v && typeof v === 'object' && !Array.isArray(v));

// 중복 제거
const seen = new Set();
const uniq = [];
for (const o of merged) {
  const k = makeKey(o);
  if (!k) continue;
  if (seen.has(k)) continue;
  seen.add(k);
  uniq.push(o);
}

// ✅ No output 방지: 결과가 0이면 더미 1개 내보내기(원치 않으면 이 블록 삭제)
if (uniq.length === 0) {
  return [{
    json: {
      _noResults: true,
      기관명: $('데이터 입력 설정').first().json.agencyName,
      message: 'AI Agent 결과에서 적합 사례가 없거나 JSON 파싱에 실패했습니다.'
    }
  }];
}

// 각 항목을 개별 아이템으로 반환
return uniq.map((item, index) => ({
  json: {
    일련번호: index + 1,
    기관명: $('데이터 입력 설정').first().json.agencyName,
    ...item,
  }
}));

// startPositions 배열을 아이템 목록으로 펼치기
const base = $input.first().json;
const starts = base.startPositions || [0, 10, 20];

return starts.map((s) => ({
  json: {
    ...base,
    start: s,
  },
}));

// SerpAPI 검색 결과 파싱
const serpResults = $input.first().json;

// google_news 엔진: news_results / google 엔진: organic_results
const items = serpResults.news_results 
  || serpResults.organic_results 
  || serpResults.top_stories 
  || [];

console.log('결과 필드:', 
  serpResults.news_results ? 'news_results' :
  serpResults.organic_results ? 'organic_results' :
  serpResults.top_stories ? 'top_stories' : '없음'
);
console.log('결과 수:', items.length);

return items.map(item => ({
  json: {
    title: item.title || '',
    link: item.link || item.url || '',
    snippet: item.snippet || item.description || '',
    date: item.date || '',
    source: '구글'
  }
}));

// 검색 결과에서 중복 제거
const items = $input.all();
const seen = new Set();
const uniqueItems = [];

for (const item of items) {
  const data = item.json;

  // URL 또는 제목을 기준으로 중복 체크
  const link = data.link || '';
  const title = data.title || '';

  // URL이 있으면 URL로 중복 체크, 없으면 제목으로 체크
  const identifier = link || title;

  if (identifier && !seen.has(identifier)) {
    seen.add(identifier);
    uniqueItems.push(item);
  }
}

console.log(`전체 ${items.length}개 중 ${uniqueItems.length}개의 고유 결과 발견`);
console.log(`${items.length - uniqueItems.length}개의 중복 제거됨`);

return uniqueItems;

const webhook = $('Webhook').first().json;
const body = webhook.body || webhook;

return [{
  json: {
    tracking_id: body.tracking_id || ""
  },
  binary: $input.item.binary
}];

